import {
	CameraOutlined,
	CloseOutlined,
	ReloadOutlined,
} from "@ant-design/icons";
import { Button, Input, Modal, Progress, Segmented } from "antd";
import {
	cloneElement,
	isValidElement,
	type ReactElement,
	type MouseEvent as ReactMouseEvent,
	type ReactNode,
} from "react";

import {
	type FeedbackCopy,
	type FeedbackKind,
	type FeedbackReport,
	formatSize,
	type ProgressFn,
	type UseFeedbackOptions,
	useFeedback,
} from "@/lib/feedback/use-feedback";

// The antd skin of the feedback flow: a single file that binds the headless
// core (`@/lib/feedback/use-feedback`) to native antd primitives — Modal,
// Segmented, Input.TextArea, Progress, and @ant-design/icons — with no
// Tailwind, no `lc-` accent CSS, and no lucide. `kind.accent` is ignored; antd
// paints from its own theme. Every string comes from `fb.copy`, and the
// behaviour contract is identical to the base-ui skin (see skin-contract.md and
// skin-conformance.test.tsx).
//
// Vendor this and edit it. Deep styling is antd theming (ConfigProvider /
// theme tokens), not a classNames map — that is why this skin takes `className`
// but no per-node class hooks.
//
// Not expected to change without care: `data-capture-hide` on the modal
// content (via modalRender). That marker is how lib/feedback/capture leaves
// this dialog out of its own screenshot; drop it and every capture is a picture
// of the feedback form.

export type {
	FeedbackCopy,
	FeedbackKind,
	FeedbackReport,
	ProgressFn,
} from "@/lib/feedback/use-feedback";

/** Props for {@link FeedbackButton} (antd skin). */
export type FeedbackButtonProps = {
	/**
	 * Deliver the assembled report. The only required prop. Rejecting returns
	 * the dialog to compose with the rejection's message shown; resolving lands
	 * it in the sent phase.
	 */
	onSubmit: (report: FeedbackReport, progress: ProgressFn) => Promise<void>;
	/** Gather the diagnostic manifest that rides along; omit to send none. */
	collectContext?: UseFeedbackOptions["collectContext"];
	/**
	 * Capture the page automatically when the dialog opens. Failures are silent.
	 * @default false
	 */
	autoCapture?: boolean;
	/**
	 * The kinds offered in the picker. Exactly one hides the picker and files
	 * every report under it.
	 * @default DEFAULT_KINDS
	 */
	kinds?: readonly FeedbackKind[];
	/** Copy overrides, merged over DEFAULT_COPY key by key. */
	copy?: Partial<FeedbackCopy>;
	/** Replaces the glyph in the default trigger. Ignored when `trigger` is set. */
	icon?: ReactNode;
	/**
	 * Replaces the default floating button entirely. The open handler is wired
	 * onto whatever element you pass — your own `onClick` runs first, and
	 * `preventDefault()` in it suppresses the open.
	 */
	trigger?: ReactNode;
	/** Extra class for the trigger button. */
	className?: string;
};

/** A trigger element we are allowed to wire an open handler onto. */
type TriggerProps = {
	onClick?: (event: ReactMouseEvent<HTMLElement>) => void;
};

/**
 * Attach `open` to the consumer's trigger, preserving its own handler. A
 * trigger that is not an element (a bare string, say) is wrapped in an antd
 * Button instead.
 */
function withOpenHandler(
	trigger: ReactNode,
	open: () => void,
	className?: string,
): ReactNode {
	if (!isValidElement(trigger)) {
		return (
			<Button htmlType="button" onClick={open} className={className}>
				{trigger}
			</Button>
		);
	}

	const element = trigger as ReactElement<TriggerProps>;
	return cloneElement(element, {
		onClick: (event: ReactMouseEvent<HTMLElement>) => {
			element.props.onClick?.(event);
			if (!event.defaultPrevented) open();
		},
	});
}

/**
 * A floating button that opens a native antd feedback dialog: pick a kind,
 * write, attach the page as a screenshot, send.
 *
 * ```tsx
 * <FeedbackButton
 *   onSubmit={async (report, progress) => {
 *     progress("Uploading…");
 *     await api.submitReport(report);
 *   }}
 * />
 * ```
 *
 * Mount it once, near the root — it positions itself and portals its dialog.
 */
export function FeedbackButton({
	onSubmit,
	collectContext,
	autoCapture = false,
	kinds,
	copy: copyOverrides,
	icon = "✦",
	trigger,
	className,
}: FeedbackButtonProps) {
	const fb = useFeedback({
		onSubmit,
		collectContext,
		autoCapture,
		kinds,
		copy: copyOverrides,
	});

	// Evaluated at render, so a function receipt can name live values; undefined
	// drops the line entirely.
	const receipt =
		typeof fb.copy.receipt === "function" ? fb.copy.receipt() : fb.copy.receipt;

	return (
		<>
			{trigger === undefined ? (
				<Button
					size="large"
					onClick={fb.launch}
					className={className}
					style={{ position: "fixed", bottom: 16, left: 16, zIndex: 40 }}
				>
					{/* The glyph is decorative, so the button's accessible name is the
					    label alone — the same contract the base-ui trigger keeps. */}
					<span aria-hidden="true">{icon}</span>
					{fb.copy.triggerLabel ?? fb.copy.title}
				</Button>
			) : (
				withOpenHandler(trigger, fb.launch, className)
			)}

			<Modal
				open={fb.open}
				onCancel={() => fb.setOpen(false)}
				afterOpenChange={fb.notifyOpenComplete}
				footer={null}
				title={fb.phase === "sent" ? fb.copy.sentTitle : fb.copy.title}
				// Keeps this dialog out of its own screenshot; see lib/feedback/capture.
				modalRender={(node) => <div data-capture-hide="">{node}</div>}
			>
				{fb.phase === "sent" ? (
					<div style={{ display: "grid", gap: 16, paddingTop: 8 }}>
						<p>{fb.copy.sentDescription}</p>
						<div style={{ display: "flex", justifyContent: "flex-end" }}>
							<Button type="primary" onClick={() => fb.setOpen(false)}>
								{fb.copy.doneLabel}
							</Button>
						</div>
					</div>
				) : (
					<div style={{ display: "grid", gap: 16, paddingTop: 8 }}>
						<p>{fb.copy.description}</p>

						{/* One kind is not a choice: file everything under it and spend
						    the space on the message instead. */}
						{fb.kinds.length > 1 && (
							<Segmented
								block
								aria-label={fb.copy.kindGroupLabel}
								value={fb.kind.value}
								onChange={(value) => fb.setKind(String(value))}
								disabled={fb.sending}
								options={fb.kinds.map((option) => ({
									label: option.label,
									value: option.value,
								}))}
							/>
						)}

						<Input.TextArea
							value={fb.message}
							onChange={(event) => fb.setMessage(event.target.value)}
							disabled={fb.sending}
							autoFocus
							aria-label={fb.copy.messageLabel}
							placeholder={fb.kind.placeholder}
							autoSize={{ minRows: 4, maxRows: 8 }}
						/>

						{/* Live, because the capture is asynchronous and its outcome — a
						    thumbnail appearing — is otherwise silent. */}
						<div aria-live="polite">
							{fb.screenshot === null ? (
								<Button
									// The glyph is decorative; antd icons carry their own
									// aria-label, so hide it or it joins the button's name.
									icon={<CameraOutlined aria-hidden />}
									onClick={fb.capture}
									disabled={fb.capturing || fb.sending}
								>
									{fb.capturing ? fb.copy.capturingLabel : fb.copy.captureLabel}
								</Button>
							) : (
								<div style={{ display: "flex", alignItems: "center", gap: 8 }}>
									{fb.screenshotUrl !== null && (
										// Decorative: the row already names what was caught and
										// how big it is, which is all a screen reader can use.
										<img
											src={fb.screenshotUrl}
											alt=""
											style={{
												width: 64,
												height: 40,
												objectFit: "cover",
												borderRadius: 6,
												border: "1px solid rgba(0,0,0,0.1)",
											}}
										/>
									)}
									<span style={{ flex: 1 }}>
										{fb.copy.attached(formatSize(fb.screenshot.length))}
									</span>
									<Button
										icon={<ReloadOutlined aria-hidden />}
										aria-label={fb.copy.retakeLabel}
										onClick={fb.capture}
										disabled={fb.capturing || fb.sending}
									/>
									<Button
										icon={<CloseOutlined aria-hidden />}
										aria-label={fb.copy.discardLabel}
										onClick={fb.discardScreenshot}
										disabled={fb.sending}
									/>
								</div>
							)}
						</div>

						{/* An alert rather than a status: every error here is the direct
						    result of something the reporter just did. */}
						{fb.error !== null && (
							<p role="alert" style={{ color: "#ff4d4f", margin: 0 }}>
								{fb.error}
							</p>
						)}

						{fb.sending && (
							<div>
								<Progress percent={Math.round(fb.percent)} showInfo={false} />
								{/* Announced on change, so a send the reporter is not
								    watching still speaks. */}
								<p aria-live="polite" style={{ margin: 0, minHeight: 20 }}>
									{fb.stage}
								</p>
							</div>
						)}

						<div
							style={{
								display: "flex",
								alignItems: "center",
								gap: 12,
								justifyContent:
									receipt === undefined ? "flex-end" : "space-between",
							}}
						>
							{receipt !== undefined && (
								<span style={{ fontSize: 12, opacity: 0.65 }}>{receipt}</span>
							)}
							<div style={{ display: "flex", gap: 8 }}>
								<Button onClick={() => fb.setOpen(false)}>
									{fb.copy.cancelLabel}
								</Button>
								<Button
									type="primary"
									onClick={fb.send}
									disabled={fb.sending || fb.message.trim() === ""}
								>
									{fb.copy.sendLabel}
								</Button>
							</div>
						</div>
					</div>
				)}
			</Modal>
		</>
	);
}

import { useCallback, useEffect, useRef, useState } from "react";
import { afterPaint, captureViewport } from "@/lib/feedback/capture";
import {
	DEFAULT_COPY,
	DEFAULT_KINDS,
	type FeedbackCopy,
	type FeedbackKind,
	type FeedbackReport,
} from "@/lib/feedback/feedback-defaults";

// The headless core of the feedback flow: one hook, `useFeedback`, that owns
// everything a skin renders from — dialog open state, the compose draft (kind,
// message, screenshot), the capture flow, and the send pipeline — and holds no
// markup of its own. A skin binds this to a design system; two ship (base-ui,
// antd) and more are a port away. See skin-contract.md next to this file.
//
// Vendor this and read it, but edit it with care: the guarantees a skin leans
// on live here, not in the JSX. The send pipeline is folded in as private
// machinery (useSendPipeline, unexported below) so there is one hook to wire,
// not two.
//
// Expected to change: the pacing constants (trickle interval, ceiling, jump
// size, completion hold) and MAX_SCREENSHOT_BYTES, to match your transport.
//
// Not expected to change without care:
//   - The generation guards. Only the current attempt may move the UI — a late
//     progress() from a leaked request cannot nudge a finished bar, and an
//     attempt the reporter walked away from cannot drag the dialog into `sent`
//     or post an error over the report they are writing now. The same discipline
//     covers capture: a clone that resolves after a close/reopen is dropped.
//   - The retry stamp. A retry reuses the first attempt's `submittedAt`, so a
//     server keying on it collapses the resend onto one row.
//   - The blob-URL lifecycle. `screenshotUrl` is revoked when the bytes change
//     or the hook unmounts; a skin must not build its own object URL.

export type {
	FeedbackCopy,
	FeedbackKind,
	FeedbackReport,
} from "@/lib/feedback/feedback-defaults";

/** Where the flow is: composing a report, sending it, or done. */
export type FeedbackPhase = "compose" | "sending" | "sent";

/**
 * What the compose form owns. The pipeline supplies the other two fields of a
 * {@link FeedbackReport} — the diagnostic manifest and the submit stamp.
 */
export type FeedbackDraft = Pick<
	FeedbackReport,
	"type" | "message" | "screenshotPng"
>;

/**
 * Report the stage a long send has reached, e.g. `"Uploading screenshot…"`.
 * The label is shown under the bar and the bar advances toward its ceiling.
 * Calling this after the send has settled is a no-op, always.
 */
export type ProgressFn = (label: string) => void;

/** Inputs to {@link useSendPipeline}. */
type SendPipelineOptions = {
	/**
	 * Deliver the report. Rejecting returns the flow to `compose` with the
	 * rejection's message surfaced; resolving completes the bar and lands in
	 * `sent`. Call the supplied `progress` as often as the transport can say
	 * something useful — a send that never calls it still animates.
	 */
	onSubmit: (report: FeedbackReport, progress: ProgressFn) => Promise<void>;
	/**
	 * Gather the diagnostic manifest that rides along, already serialized and
	 * scrubbed. Runs at the head of every attempt (including a retry), so the
	 * manifest describes the browser at send time. Omit to send no context.
	 */
	collectContext?: () => string | null | Promise<string | null>;
	/**
	 * Override the strings this hook produces: `collectingLabel` (the first
	 * stage), `progressLabel` (held when the consumer never calls `progress`),
	 * and `errorFallback` (used when a rejection carries no usable message).
	 */
	copy?: Partial<FeedbackCopy>;
};

/** Everything the send pipeline surfaces to the flow above it. */
type SendPipeline = {
	/** Which phase the flow is in. */
	phase: FeedbackPhase;
	/** Bar fill, 0–100. Zero outside a send; exactly 100 once one succeeds. */
	percent: number;
	/** Current stage label; empty string outside a send. */
	stage: string;
	/** Message from the last failed attempt, or null. */
	error: string | null;
	/** The stamp the current report will carry, or null before the first send. */
	submittedAt: number | null;
	/** Run the pipeline. Ignored while a send is already in flight. */
	send: (draft: FeedbackDraft) => Promise<void>;
	/** Discard all send state, so the next `send` starts a fresh report. */
	reset: () => void;
};

// Where the bar starts, so it is visible the instant a send begins.
const START_PERCENT = 8;
// The bar's self-driven ceiling. It approaches this asymptotically and only
// ever reaches 100 because the send actually finished — an honest bar never
// claims a completion it hasn't observed.
const CEILING = 90;
// How often the bar advances on its own.
const TRICKLE_INTERVAL_MS = 200;
// Each tick closes this fraction of the gap to the ceiling, which is what
// makes the motion decelerate: constant time, shrinking distance.
const TRICKLE_FRACTION = 0.08;
// A progress() call is worth a visible jump — several ticks' worth.
const STAGE_FRACTION = 0.35;
// How long a full bar is held before the sent phase replaces it, so the
// completion registers instead of flashing past.
const COMPLETE_HOLD_MS = 450;

/** Close `fraction` of the distance from `from` to the ceiling. */
function toward(from: number, fraction: number): number {
	return from + (CEILING - from) * fraction;
}

/** A rejection's own message, or the generic fallback when it hasn't one. */
function messageFor(reason: unknown, fallback: string): string {
	return reason instanceof Error && reason.message.trim() !== ""
		? reason.message
		: fallback;
}

/**
 * Own the send half of a feedback dialog: phases, a self-advancing progress
 * bar, stage labels, and errors. Private to this file — a consumer wires
 * {@link useFeedback}, which folds this in.
 *
 * Call `reset()` when the dialog opens: that clears the previous outcome and
 * releases the stamp, so the next send files a new report rather than
 * retrying the last one.
 */
function useSendPipeline(options: SendPipelineOptions): SendPipeline {
	const [phase, setPhase] = useState<FeedbackPhase>("compose");
	const [percent, setPercent] = useState(0);
	const [stage, setStage] = useState("");
	const [error, setError] = useState<string | null>(null);
	const [submittedAt, setSubmittedAt] = useState<number | null>(null);

	// Read at send time rather than captured, so `send` stays referentially
	// stable while still seeing the caller's latest closures.
	const optionsRef = useRef(options);
	useEffect(() => {
		optionsRef.current = options;
	});

	// The mechanism behind "only the current attempt may move the UI": every
	// attempt takes a generation number, and settling — or a reset, or a later
	// send — increments the counter. The `progress` handed to `onSubmit` and
	// both of the attempt's own settle paths compare their captured number
	// against the counter and do nothing once they differ, so a leaked callback
	// or an abandoned promise is inert no matter how long it takes to arrive.
	const generation = useRef(0);
	// Covers the whole in-flight window, including the completion hold — a
	// state flag would lag a synchronous double-click.
	const busy = useRef(false);
	const stampRef = useRef<number | null>(null);
	const trickle = useRef<ReturnType<typeof setInterval> | null>(null);
	const hold = useRef<ReturnType<typeof setTimeout> | null>(null);

	const stopClocks = useCallback(() => {
		if (trickle.current !== null) clearInterval(trickle.current);
		if (hold.current !== null) clearTimeout(hold.current);
		trickle.current = null;
		hold.current = null;
	}, []);

	useEffect(() => stopClocks, [stopClocks]);

	const reset = useCallback(() => {
		generation.current += 1;
		stopClocks();
		busy.current = false;
		stampRef.current = null;
		setPhase("compose");
		setPercent(0);
		setStage("");
		setError(null);
		setSubmittedAt(null);
	}, [stopClocks]);

	const send = useCallback(
		async (draft: FeedbackDraft) => {
			if (busy.current) return;
			busy.current = true;

			generation.current += 1;
			const run = generation.current;
			const copy = { ...DEFAULT_COPY, ...optionsRef.current.copy };

			// Held across attempts: a retry must reach the server with the
			// original stamp or it files a second row.
			const stamp = stampRef.current ?? Date.now();
			stampRef.current = stamp;
			setSubmittedAt(stamp);

			setError(null);
			setPhase("sending");
			setStage(copy.collectingLabel);
			setPercent(START_PERCENT);

			stopClocks();
			const ownTrickle = setInterval(() => {
				if (generation.current !== run) return;
				setPercent((p) => toward(p, TRICKLE_FRACTION));
			}, TRICKLE_INTERVAL_MS);
			trickle.current = ownTrickle;

			/**
			 * Settle once. This run's own trickle is always cleared, whoever it
			 * belongs to now; everything else happens only while this run is still
			 * the current one. `false` means the run was superseded — by a reset or
			 * a later send — and the caller must touch no state at all, or a send
			 * the reporter walked away from redraws the dialog over the report they
			 * are writing now.
			 */
			const finish = (): boolean => {
				clearInterval(ownTrickle);
				if (trickle.current === ownTrickle) trickle.current = null;
				if (generation.current !== run) return false;
				generation.current += 1;
				stopClocks();
				return true;
			};

			try {
				const collect = optionsRef.current.collectContext;
				const contextJson = collect ? await collect() : null;
				if (generation.current === run) setStage(copy.progressLabel);

				await optionsRef.current.onSubmit(
					{ ...draft, contextJson, submittedAt: stamp },
					(label) => {
						if (generation.current !== run) return;
						setStage(label);
						setPercent((p) => toward(p, STAGE_FRACTION));
					},
				);

				if (!finish()) return;
				setPercent(100);
				hold.current = setTimeout(() => {
					busy.current = false;
					setPhase("sent");
				}, COMPLETE_HOLD_MS);
			} catch (reason) {
				if (!finish()) return;
				busy.current = false;
				setPercent(0);
				setStage("");
				setPhase("compose");
				setError(messageFor(reason, copy.errorFallback));
			}
		},
		[stopClocks],
	);

	return { phase, percent, stage, error, submittedAt, send, reset };
}

/**
 * Cap an attachment rather than let it fail the whole report.
 *
 * The rule: pick the largest raw PNG whose *encoded* size still clears
 * whatever your transport accepts, then set this below it. Encodings inflate —
 * base64 by about a third — and the manifest rides in the same request, so the
 * raw ceiling is meaningfully lower than the request limit. 10 MiB suits a
 * 16 MiB base64 request cap; retune it against your own server the moment you
 * know that number, because the failure it prevents is a report the reporter
 * already wrote being rejected whole.
 */
const MAX_SCREENSHOT_BYTES = 10 * 1024 * 1024;

/**
 * Bytes as a short human string, for the attachment row and the size error. A
 * skin renders it into `copy.attached(...)`; the hook renders it into the
 * size-cap error itself.
 */
export function formatSize(bytes: number): string {
	return bytes >= 1024 * 1024
		? `${(bytes / (1024 * 1024)).toFixed(1)} MB`
		: `${Math.max(1, Math.round(bytes / 1024))} KB`;
}

/** Inputs to {@link useFeedback}. */
export type UseFeedbackOptions = {
	/**
	 * Deliver the assembled report. The only required option. Rejecting returns
	 * the dialog to compose with the rejection's message shown; resolving lands
	 * it in the sent phase. Call the supplied `progress` as the transport learns
	 * something — a send that never calls it still animates.
	 */
	onSubmit: (report: FeedbackReport, progress: ProgressFn) => Promise<void>;
	/**
	 * Gather the diagnostic manifest that rides along, already serialized and
	 * scrubbed. Runs at the head of every attempt, so it describes the browser
	 * at send time. Omit and `report.contextJson` is null.
	 */
	collectContext?: SendPipelineOptions["collectContext"];
	/**
	 * The kinds offered in the picker, each with its own accent and placeholder.
	 * Exactly one kind hides the picker entirely and files every report under
	 * it; an empty list falls back to {@link DEFAULT_KINDS}.
	 * @default DEFAULT_KINDS
	 */
	kinds?: readonly FeedbackKind[];
	/**
	 * Copy overrides, merged over {@link DEFAULT_COPY} key by key, so supplying
	 * one string leaves the rest alone.
	 */
	copy?: Partial<FeedbackCopy>;
	/**
	 * Capture the page automatically when the dialog opens, so the reporter has
	 * an attachment without asking for one. Failures are silent.
	 * @default false
	 */
	autoCapture?: boolean;
};

/**
 * Everything a skin renders from and drives the flow through. The skin owns
 * only markup; every piece of state and every transition lives here.
 */
export type Feedback = {
	/** Whether the dialog is open. */
	open: boolean;
	/** Which phase the flow is in. */
	phase: FeedbackPhase;
	/** True during a send — inputs lock and the progress bar shows. */
	sending: boolean;
	/** The resolved kind list the skin renders; never empty. */
	kinds: readonly FeedbackKind[];
	/** The currently selected kind. */
	kind: FeedbackKind;
	/** The prose written so far. */
	message: string;
	/** The attached PNG bytes, or null when nothing is attached. */
	screenshot: Uint8Array | null;
	/** A blob URL for the thumbnail, or null; lifecycle managed by the hook. */
	screenshotUrl: string | null;
	/** True while a capture is in flight. */
	capturing: boolean;
	/** Bar fill, 0–100. */
	percent: number;
	/** Current stage label. */
	stage: string;
	/** The one error line to show, or null. Capture errors take priority. */
	error: string | null;
	/** Fully merged copy — every key present; skins read all strings here. */
	copy: FeedbackCopy;
	/** Open onto an empty form; the next send stamps a fresh report. */
	launch: () => void;
	/** The dismissal path; retires any capture still in flight. */
	setOpen: (next: boolean) => void;
	/** Wire to the dialog's open-complete callback; fires the armed auto-capture. */
	notifyOpenComplete: (open: boolean) => void;
	/** Select a kind by value. */
	setKind: (value: string) => void;
	/** Replace the prose. */
	setMessage: (value: string) => void;
	/** Take (or retake) a capture, surfacing failures. */
	capture: () => void;
	/** Drop the attachment. */
	discardScreenshot: () => void;
	/** Start the send. */
	send: () => void;
};

/**
 * The headless feedback flow: a compose draft, a capture flow, and a staged
 * send, with no markup. A skin renders the returned {@link Feedback}.
 *
 * ```tsx
 * const fb = useFeedback({
 *   onSubmit: async (report, progress) => {
 *     progress("Uploading…");
 *     await api.submitReport(report);
 *   },
 * });
 * ```
 */
export function useFeedback(options: UseFeedbackOptions): Feedback {
	const {
		onSubmit,
		collectContext,
		autoCapture = false,
		kinds = DEFAULT_KINDS,
		copy: copyOverrides,
	} = options;

	const copy = { ...DEFAULT_COPY, ...copyOverrides };
	// An empty list would leave the dialog with nothing to file under, so it
	// falls back rather than rendering a form that cannot produce a report.
	const resolvedKinds = kinds.length > 0 ? kinds : DEFAULT_KINDS;

	const [open, setOpenState] = useState(false);
	const [type, setType] = useState(resolvedKinds[0].value);
	const [message, setMessage] = useState("");
	const [screenshot, setScreenshot] = useState<Uint8Array | null>(null);
	const [screenshotUrl, setScreenshotUrl] = useState<string | null>(null);
	const [capturing, setCapturing] = useState(false);
	// An auto-capture waiting for the dialog to finish opening. A ref, not state:
	// nothing renders from it, and it is read inside a dialog callback.
	const armed = useRef(false);
	const [captureError, setCaptureError] = useState<string | null>(null);
	// The generation guard for `capture`, the one async path in the compose
	// half: every open and every close bumps the counter, and a capture captures
	// it at the top and drops its result if it no longer matches — so a clone
	// that resolves after the reporter closed or reopened the dialog can't
	// attach a screenshot of the wrong page, or an error, onto a fresh form.
	const captureRun = useRef(0);

	const pipeline = useSendPipeline({ onSubmit, collectContext, copy });

	const kind =
		resolvedKinds.find((option) => option.value === type) ?? resolvedKinds[0];

	// The preview is a blob URL that has to be released, so it is derived here
	// rather than built inline. Absent createObjectURL — a non-browser render
	// target — the attachment row simply has no thumbnail.
	useEffect(() => {
		if (screenshot === null || typeof URL.createObjectURL !== "function") {
			setScreenshotUrl(null);
			return;
		}
		// The cast is the DOM lib's SharedArrayBuffer caveat, not a real
		// mismatch: captureViewport only ever returns a plain, non-shared view.
		const url = URL.createObjectURL(
			new Blob([screenshot as BlobPart], { type: "image/png" }),
		);
		setScreenshotUrl(url);
		return () => {
			URL.revokeObjectURL(url);
		};
	}, [screenshot]);

	/**
	 * Attach the page behind the dialog.
	 *
	 * `silent` is the whole difference between the two ways this is reached, and
	 * the asymmetry is deliberate. A manual capture is something the reporter
	 * asked for and is waiting on, so a failure has to be said out loud. An
	 * automatic one they never asked for; an error about it would be the first
	 * thing they read in a dialog they opened to write a sentence, about a
	 * nicety, when the manual button sitting right there is the retry. So the
	 * automatic path swallows both failure modes — a render that throws and a
	 * capture over the size cap — and leaves the form as if it had never run.
	 */
	const capture = useCallback(
		async (silent: boolean) => {
			// Captured before the await; the clone can outlive the dialog it was
			// taken for, and a `run` that no longer matches means the reporter has
			// moved on.
			const run = captureRun.current;
			const current = () => captureRun.current === run;
			if (!silent) setCaptureError(null);
			setCapturing(true);
			try {
				const bytes = await captureViewport();
				if (!current()) return;
				if (bytes.length > MAX_SCREENSHOT_BYTES) {
					if (!silent) {
						setCaptureError(
							copy.tooLarge(
								formatSize(bytes.length),
								formatSize(MAX_SCREENSHOT_BYTES),
							),
						);
					}
					return;
				}
				setScreenshot(bytes);
			} catch {
				if (current() && !silent) setCaptureError(copy.captureFailed);
			} finally {
				if (current()) setCapturing(false);
			}
		},
		// copy is re-created each render but its strings only change when the
		// caller changes `copy`; capture reads them lazily inside the closure.
		[copy.tooLarge, copy.captureFailed],
	);

	/** Open onto an empty form; the next send stamps a fresh report. */
	const launch = () => {
		pipeline.reset();
		// Retires any capture still in flight from a prior open, so its result
		// can't land on the fresh form this opens onto.
		captureRun.current += 1;
		setType(resolvedKinds[0].value);
		setMessage("");
		setScreenshot(null);
		setCapturing(false);
		setCaptureError(null);
		setOpenState(true);
		// Armed here, fired from notifyOpenComplete once the dialog has finished
		// animating open. The clone blocks the main thread for as long as it runs,
		// so starting it in this tick freezes the dialog's own enter animation and
		// the open reads as a stall — deferring by a frame is not enough, because
		// the animation spans many. `capturing` is still set synchronously, so the
		// footer reads as pending from the first frame rather than flashing the
		// attach button and swapping.
		if (autoCapture) {
			armed.current = true;
			setCapturing(true);
		}
	};

	/** The dismissal path — Escape, the overlay, the Cancel button all pass here. */
	const setOpen = (next: boolean) => {
		// The one place to retire a capture still in flight before it can attach
		// to whatever the dialog shows next.
		if (!next) captureRun.current += 1;
		setOpenState(next);
	};

	/**
	 * Run the armed auto-capture, now that nothing is animating for it to block.
	 *
	 * `afterPaint` buys one more frame so the animation's last frame is on screen
	 * before the main thread goes away, and — the reason it is a raced timeout
	 * rather than a bare rAF — settles even if the tab is hidden by now, which
	 * would otherwise pause frame callbacks and strand the capture forever.
	 */
	const notifyOpenComplete = (isOpen: boolean) => {
		if (!isOpen || !armed.current) return;
		armed.current = false;
		void afterPaint().then(() => capture(true));
	};

	const send = () => {
		setCaptureError(null);
		void pipeline.send({ type, message, screenshotPng: screenshot });
	};

	return {
		open,
		phase: pipeline.phase,
		sending: pipeline.phase === "sending",
		kinds: resolvedKinds,
		kind,
		message,
		screenshot,
		screenshotUrl,
		capturing,
		percent: pipeline.percent,
		stage: pipeline.stage,
		// Capture error takes priority: it is the direct result of something the
		// reporter just did, and it sits over any stale send error.
		error: captureError ?? pipeline.error,
		copy,
		launch,
		setOpen,
		notifyOpenComplete,
		setKind: setType,
		setMessage,
		capture: () => void capture(false),
		discardScreenshot: () => setScreenshot(null),
		send,
	};
}

import type { ReactNode } from "react";

export type FeedbackReport = {
	/** Matches the `value` of one of the offered kinds. */
	type: string;
	/** The prose the reporter typed. */
	message: string;
	/** PNG bytes of an attached capture, or null when none was taken. */
	screenshotPng: Uint8Array | null;
	/** Serialized diagnostic manifest, or null when none was collected. */
	contextJson: string | null;
	/** Epoch milliseconds; stable across retries of the same report. */
	submittedAt: number;
};

/*
 * FeedbackReport, above, is one assembled report — the value handed to the
 * consumer's `onSubmit`. It heads the declarations because `shadcn add` strips
 * every comment above a file's imports, so the notes below have to sit under
 * something to reach a consumer at all.
 *
 * `submittedAt` is stamped once per dialog open and survives a retry, so a
 * server that keys on (user, submittedAt) collapses a resend of a failed
 * report onto the same row instead of filing a duplicate. Millisecond
 * granularity is enough because a human cannot complete two compose cycles
 * inside one millisecond; each genuine report re-opens the dialog and
 * re-stamps.
 */

// The customization map for the feedback flow: every piece of copy the dialog
// renders, the report kinds it offers, and the shapes those two travel in.
// This is the first — and for most consumers the only — file to edit after
// vendoring. Nothing here does any work; it is data plus types.
//
// Expected to change: all of it. DEFAULT_COPY is deliberately product-neutral
// so it reads as placeholder text rather than someone else's voice — replace
// it with your own. DEFAULT_KINDS is a two-entry starting point; add, remove,
// or re-label entries freely, and give each one an `accent` that suits your
// palette.
//
// Not expected to change: the FeedbackReport shape. It is the contract with
// the server — an `onSubmit` maps those five fields onto a request, and
// `submittedAt` in particular is idempotency material (see the note above).
// The types live here rather than beside the hook so that a consumer's
// wrapper can import them without pulling the component in. The one React
// reference is a type-only `ReactNode` import, which erases at compile time.

/**
 * One selectable report kind.
 *
 * `accent` is any CSS color; it is applied as `--lc-accent`, so it paints the
 * dialog's hairline ring and bloom, not text. `placeholder` seeds the message
 * field when that kind is selected.
 */
export type FeedbackKind = {
	value: string;
	label: string;
	accent?: string;
	placeholder?: string;
};

/**
 * Every piece of copy the flow renders.
 *
 * Three fields are more than a string, because the markup they land in is the
 * consumer's to shape: `title` takes any node, `receipt` takes a node-returning
 * function, and `triggerLabel` splits the floating button's wording off from
 * the dialog heading. Two more — `attached` and `tooLarge` — are functions
 * only because they interpolate a formatted byte size the flow computes; they
 * still return plain strings. The rest are plain strings and are meant to stay
 * that way — they land in places (a `<Button>`'s label, an `aria-label`) where
 * a node buys nothing.
 */
export type FeedbackCopy = {
	/**
	 * Dialog heading in the compose phase. Any node: a lone string, or markup —
	 * an accent-colored glyph ahead of the words, say. Base UI names the dialog
	 * from this element via `aria-labelledby`, and that name is computed from
	 * the rendered subtree, so mark decorative glyphs `aria-hidden` and the
	 * accessible name stays the words alone.
	 */
	title: ReactNode;
	/** Sub-heading under the compose title. */
	description: string;
	/**
	 * The floating trigger's wording, and its accessible name. Omit it and the
	 * trigger falls back to `title`, so a consumer who wants one phrase in both
	 * places writes it once; set it when the button and the heading should read
	 * differently ("Feedback" on the button, "Send Word" over the form).
	 *
	 * Plain string on purpose: this is the button's whole accessible name, and
	 * an `aria-hidden` glyph inside a node would silently shorten it. The
	 * trigger already renders `icon` ahead of this label.
	 */
	triggerLabel?: string;
	/** Button that attaches a screenshot. */
	captureLabel: string;
	/** Shown on the capture control while a capture is in flight. */
	capturingLabel: string;
	/** Accessible name for the control that replaces an attachment. */
	retakeLabel: string;
	/** Accessible name for the control that drops an attachment. */
	discardLabel: string;
	/** Line naming the attached capture and its size, e.g. `"Screenshot attached (200 KB)"`. */
	attached: (size: string) => string;
	/** Shown when a capture clears rendering but exceeds the size cap. */
	tooLarge: (size: string, limit: string) => string;
	/** Shown when the page will not render to an image at all. */
	captureFailed: string;
	/** Accessible name for the kind toggle group. */
	kindGroupLabel: string;
	/** Accessible name for the message field. */
	messageLabel: string;
	/** Button that dismisses the dialog. */
	cancelLabel: string;
	/** Button that starts the send pipeline. */
	sendLabel: string;
	/** Dialog heading once the report is filed. */
	sentTitle: string;
	/** Sub-heading under the sent title. */
	sentDescription: string;
	/** Button that closes the dialog from the sent phase. */
	doneLabel: string;
	/** First stage label, shown while the diagnostic manifest is gathered. */
	collectingLabel: string;
	/** Stage label held for the rest of a send that never calls `progress()`. */
	progressLabel: string;
	/** Shown when a rejection carries no usable message of its own. */
	errorFallback: string;
	/**
	 * Optional line naming what rides along with the report. A bare string for a
	 * fixed line; a function to compose a live one ("carries 12 events · build
	 * a531918") that is evaluated at render rather than at module load.
	 *
	 * The function may return markup, which is the seam for a line that is not
	 * uniformly styled — a small-caps label ahead of a hex SHA that must not be,
	 * for instance. Return `undefined` and the footer drops the receipt line
	 * entirely, so a live receipt can decide it has nothing to say.
	 */
	receipt?: string | (() => ReactNode);
};

/**
 * A warm/cool pair of report kinds.
 *
 * The two accents are picked to stay visible against an unknown theme, since
 * this component ships without one. Measured as WCAG contrast against a light
 * surface (`oklch(0.97 0.005 290)`) and a dark one (`oklch(0.17 0.01 290)`):
 * the bug orange lands at 3.63:1 and 4.83:1, the idea blue at 3.33:1 and
 * 5.26:1. The bar applied is the 3:1 non-text/UI-component threshold, not the
 * 4.5:1 body-text one — these colors are only ever a hairline ring and a
 * blurred bloom, never a text color. Their hues sit 215° apart so the two
 * kinds read as different pigments at a glance rather than two shades of one.
 */
export const DEFAULT_KINDS: readonly FeedbackKind[] = [
	{
		value: "bug",
		label: "Bug",
		accent: "oklch(0.62 0.19 35)",
		placeholder: "What went wrong, and what were you doing at the time?",
	},
	{
		value: "idea",
		label: "Idea",
		accent: "oklch(0.62 0.16 250)",
		placeholder: "What would you like this to do?",
	},
];

/**
 * Product-neutral placeholder copy. Every string is meant to be replaced;
 * shipped wording is plain on purpose so an un-customized install reads as
 * unfinished rather than as another product's voice.
 */
export const DEFAULT_COPY: FeedbackCopy = {
	title: "Send feedback",
	/*
	 * No `triggerLabel` here on purpose. The field is absent rather than set to
	 * the same words, because the trigger reads `triggerLabel ?? title` — a
	 * default value here would win over the merge and leave a consumer who
	 * renamed only `title` with a button still saying "Send feedback".
	 */
	/*
	 * Deliberately says nothing about what the report carries. Whether any
	 * diagnostic manifest rides along at all is the `collectContext` prop's
	 * business, and what it contains — and whether it has been scrubbed — is
	 * known only to the consumer that wrote it. A default that promised a
	 * scrubbed record would be a lie on every install that omits the prop.
	 */
	description: "Tell us what's on your mind.",
	captureLabel: "Capture screenshot",
	capturingLabel: "Capturing…",
	retakeLabel: "Retake screenshot",
	discardLabel: "Discard screenshot",
	attached: (size) => `Screenshot attached (${size})`,
	tooLarge: (size, limit) =>
		`That capture came to ${size} — the limit is ${limit}.`,
	captureFailed: "The page wouldn't render to an image. Send the words anyway.",
	kindGroupLabel: "Feedback type",
	messageLabel: "Feedback message",
	cancelLabel: "Cancel",
	sendLabel: "Send",
	sentTitle: "Feedback sent",
	sentDescription: "Thanks — we read every report.",
	doneLabel: "Done",
	collectingLabel: "Collecting diagnostics…",
	progressLabel: "Sending…",
	errorFallback: "Something went wrong. Try again.",
};

const EXCLUDED = '[data-capture-hide],[data-slot="dialog-overlay"]';

/*
 * EXCLUDED, above, names the nodes dropped from the clone: the feedback
 * dialog's popup (marked by the component) and the backdrop that dims the page
 * behind it. A Base UI dialog is modal, so only one can be open at a time —
 * whenever this runs, the open dialog *is* the feedback one, and what's left is
 * the page the reader means. Excluding a node excludes its subtree, so an empty
 * portal wrapper may survive; it paints nothing.
 *
 * It leads the file because `shadcn add` strips every comment above the first
 * statement, so a declaration has to come first for these notes to reach a
 * consumer at all.
 */

// Captures the current viewport to PNG bytes via `modern-screenshot`, for
// attaching a visual to a bug/feedback report. The page is re-rendered into an
// off-screen SVG <foreignObject> and rasterized — no getDisplayMedia, so there
// is no picker, no permission prompt, and the feedback modal never has to close
// or blink. The browser draws the clone itself, so oklch(), color-mix() and the
// accent bloom come out as authored.
//
// Expected to change: MAX_SCALE (how much retina headroom to pay for in
// bytes) and the `domToBlob` options — width/height/type and the `fetch`
// placeholder policy are all reasonable to retune per consumer. The
// `restoreScrollPosition` feature flag should stay on for any app with
// internal scroll panes, per the comment below.
//
// Not expected to change: the EXCLUDED selector and `includeInCapture`'s
// signature. `data-capture-hide` and `data-slot="dialog-overlay"` are a
// cross-item convention — whatever dialog/modal component calls this capture
// is expected to mark its own popup and backdrop with those, and a test pins
// exactly this selector. Renaming either marker here without updating the
// dialog component (or vice versa) makes the dialog capture itself.

/** True for nodes that belong in the shot — the `filter` modern-screenshot calls. */
export function includeInCapture(node: Node): boolean {
	return !(node instanceof Element && node.matches(EXCLUDED));
}

// Fallback for afterPaint when frame callbacks are paused. Long enough that a
// live rAF (fires within ~2 frames, <35ms) always wins in the foreground, yet a
// hidden tab still proceeds promptly rather than waiting for a refocus.
const PAINT_FALLBACK_MS = 250;

/**
 * Resolves after the next paint — or after a short fallback delay when no paint
 * is coming.
 *
 * `captureViewport` blocks the main thread for as long as the clone takes, so a
 * caller that starts it in the same tick as opening a dialog freezes that
 * dialog's enter animation and the open reads as a stall. Awaiting this first
 * puts the blocking work after the paint instead.
 *
 * Browsers pause requestAnimationFrame entirely in hidden tabs, so a bare
 * double-rAF deferral would strand a caller whose tab lost visibility; the
 * timeout guarantees settlement either way. A bare `setTimeout(0)` is not a
 * substitute — it fires BEFORE the next paint, ahead of the render it defers to.
 */
export function afterPaint(): Promise<void> {
	return new Promise((resolve) => {
		const timer = setTimeout(resolve, PAINT_FALLBACK_MS);
		// Two frames: the first lets the pending render commit paint; work
		// scheduled on the second runs after it.
		requestAnimationFrame(() =>
			requestAnimationFrame(() => {
				clearTimeout(timer);
				resolve();
			}),
		);
	});
}

// Retina is worth the bytes for legible text, but a 3x display would quadruple
// the PNG for no added clarity in a bug report.
const MAX_SCALE = 2;

/**
 * Rasterize the visible viewport, minus the feedback dialog, as PNG bytes.
 *
 * Rejects if the render fails. The app shell is `h-svh` with its own internal
 * scroll panes, so the document itself never scrolls and body at viewport size
 * is exactly what the reader sees; scrolled panes inside it are offset by
 * modern-screenshot.
 *
 * Known gap: `position: sticky` doesn't survive the clone. A scrolled pane's
 * offset is faked with a transform, so there is no scrollport for sticky to
 * resolve against and a pinned header (the spell list's level heading) is
 * missing from the shot. The rows themselves are correct, which is what a
 * report is about.
 */
export async function captureViewport(): Promise<Uint8Array> {
	// Loaded on demand: ~180 KB that only a reader filing a report ever pays for,
	// and it touches `document` at call time, so it must not run during SSR.
	const { domToBlob } = await import("modern-screenshot");

	const blob = await domToBlob(document.body, {
		width: window.innerWidth,
		height: window.innerHeight,
		scale: Math.min(window.devicePixelRatio || 1, MAX_SCALE),
		type: "image/png",
		filter: includeInCapture,
		// Off by default, and without it every scroll pane in the clone snaps back
		// to the top — the spell list is one, so the shot would show the head of
		// the list instead of the rows the reader is actually looking at.
		features: { restoreScrollPosition: true },
		// A cross-origin avatar that won't hand over CORS headers leaves a gap
		// rather than failing the capture — a screenshot is a nicety, not a gate.
		fetch: { placeholderImage: "" },
	});

	return new Uint8Array(await blob.arrayBuffer());
}

export type DiagnosticEvent = {
	kind: "log" | "warn" | "error" | "window-error" | "rejection" | "rpc-error";
	message: string;
	at: number;
};

// Bounded ring buffer of client-side diagnostic events (console output,
// uncaught errors/rejections, and anything else a consumer records) plus a
// manifest assembler that folds that history together with page facts and a
// caller-supplied extra bag. Vendor this alongside a feedback/bug-report flow
// that wants a "what was happening in the browser" history to attach to a
// report.
//
// Expected to change: CAPACITY (how many recent events survive) and
// MAX_MESSAGE (how long a single message is allowed to be) are the two
// buffer knobs. Which console levels installDiagnostics patches ("log",
// "warn", "error") is a third — trim or extend that array per consumer. What
// goes into collectContext's `extra` bag is entirely the caller's call: an
// identity, a build stamp, feature flags, anything the report should carry —
// this module has no opinion and no type for it.
//
// Not expected to change: the DiagnosticEvent shape, the ring-buffer
// eviction (oldest event drops first once CAPACITY is exceeded), and the
// page.url comment below — query/hash can carry auth tokens a scrubber may
// not recognize, so only origin+pathname are ever recorded.

// Keep the last N events; a report needs the recent tail, not the whole session.
const CAPACITY = 50;
// Cap a single message so one enormous object can't bloat the manifest.
const MAX_MESSAGE = 2000;

const buffer: DiagnosticEvent[] = [];

/**
 * Append one event to the ring buffer, evicting the oldest once CAPACITY is
 * exceeded. Exported so a consumer can feed the buffer from its own
 * transport/error plumbing — e.g. an RPC client's error interceptor:
 *
 *   const recordRpcErrors = (next) => async (req) => {
 *     try { return await next(req); }
 *     catch (err) { record("rpc-error", `${req.method.name}: ${err}`); throw err; }
 *   };
 */
export function record(kind: DiagnosticEvent["kind"], message: string): void {
	buffer.push({ kind, message: message.slice(0, MAX_MESSAGE), at: Date.now() });
	if (buffer.length > CAPACITY) buffer.shift();
}

/**
 * Number of events currently buffered — lets a consumer compose a receipt
 * line ("carries N events") without parsing the manifest to count them.
 */
export function eventCount(): number {
	return buffer.length;
}

// console args arrive as unknown[]; render them to one string without throwing
// on a circular object (JSON.stringify would).
function stringifyArgs(args: unknown[]): string {
	return args
		.map((a) => {
			if (typeof a === "string") return a;
			try {
				return JSON.stringify(a);
			} catch {
				return String(a);
			}
		})
		.join(" ");
}

let installed = false;

/**
 * Patch console + window error hooks so the ring buffer fills from page load.
 * Browser-guarded and idempotent — safe to call in shared boot code that also
 * runs under SSR (where it no-ops).
 */
export function installDiagnostics(): void {
	if (installed || typeof window === "undefined") return;
	installed = true;

	for (const level of ["log", "warn", "error"] as const) {
		const original = console[level];
		console[level] = (...args: unknown[]) => {
			record(level, stringifyArgs(args));
			original.apply(console, args);
		};
	}

	window.addEventListener("error", (e) => {
		record("window-error", e.message || String(e.error));
	});
	window.addEventListener("unhandledrejection", (e) => {
		record("rejection", String(e.reason));
	});
}

/**
 * Assemble the diagnostic manifest: page facts, the recent event tail, and
 * whatever the caller passes in `extra` — identity, a build stamp, feature
 * flags, anything else the report should carry. This module has no opinion
 * and no type for `extra`; it only owns `page` and `events`. The caller
 * scrubs the result before it goes on the wire — collectContext gathers,
 * scrub() sanitizes.
 *
 * Merge precedence: `extra` is spread first, then `page`/`events` are set on
 * top, so the module's own facts always win over a same-named key in
 * `extra`. That keeps a report's page/event data intact even if a caller's
 * bag happens to use one of those names; every other key in `extra` passes
 * through untouched.
 */
export function collectContext(
	extra?: Record<string, unknown>,
): Record<string, unknown> {
	return {
		...extra,
		page: {
			// origin + pathname only: the query/hash can carry auth tokens (an
			// auth provider may append a session token or handshake param to the
			// URL on a dev instance), and a non-JWT-shaped token there would slip
			// past the scrubber. The path is all a report needs anyway.
			url:
				typeof location !== "undefined"
					? location.origin + location.pathname
					: "",
			userAgent: typeof navigator !== "undefined" ? navigator.userAgent : "",
			viewport:
				typeof window !== "undefined"
					? { width: window.innerWidth, height: window.innerHeight }
					: null,
		},
		events: buffer.slice(),
	};
}

const SENSITIVE_KEY = /token|secret|key|jwt|clerk|__session|password|auth/i;

// Privacy scrubber for a diagnostic/report payload assembled from browser
// state (console history, network logs, URLs). Such a payload can incidentally
// capture a session token or an auth header; this strips those before it ever
// leaves the browser. Two rules, applied together over the whole structure:
//   1. Drop any object key whose name suggests a credential.
//   2. Redact any string value shaped like a JWT, wherever it appears.
//
// Expected to change: SENSITIVE_KEY and JWT_SHAPED are the two knobs.
// SENSITIVE_KEY matches by case-insensitive substring, so "authToken",
// "X-Api-Key" and "__session" all hit it; it is deliberately broad, because a
// dropped benign field costs nothing and a leaked credential costs a lot. Add
// a substring to it for a new credential shape (e.g. a different auth
// provider's cookie name); add a sibling to JWT_SHAPED (with its own
// REDACTED-style replacement) for a differently-shaped secret, such as an API
// key or connection string.
//
// Not expected to change: the recursion shape (string / array / object /
// primitive) and that scrub never mutates its input — callers rely on being
// able to scrub a value and still use the original afterward.

// A JWT: three base64url segments joined by dots, with a header that always
// begins "eyJ" (base64 of `{"`). Global and unanchored so it redacts a token
// embedded ANYWHERE in a string — inside a log line ("Bearer eyJ…"), a URL
// (Clerk's ?__clerk_db_jwt=eyJ…), or a stringified object — not only a value
// that is wholly a JWT. The "eyJ" prefix is what keeps it from eating benign
// dotted strings like "1.2.3" or "react.dom.client".
const JWT_SHAPED = /eyJ[A-Za-z0-9_-]+\.[A-Za-z0-9_-]+\.[A-Za-z0-9_-]+/g;

const REDACTED = "[redacted]";

/**
 * Deep-copy `value`, dropping credential-named keys and redacting JWT-shaped
 * strings. Pure: never mutates its input. Objects created with a null prototype
 * or exotic classes are walked as plain records — the manifest is plain data.
 */
export function scrub(value: unknown): unknown {
	if (typeof value === "string") {
		return value.replace(JWT_SHAPED, REDACTED);
	}
	if (Array.isArray(value)) {
		return value.map(scrub);
	}
	if (value !== null && typeof value === "object") {
		const out: Record<string, unknown> = {};
		for (const [key, v] of Object.entries(value)) {
			if (SENSITIVE_KEY.test(key)) continue;
			out[key] = scrub(v);
		}
		return out;
	}
	return value;
}
